Bash(node -e "
// Simulate fit at common mobile widths
// Bold Inter/system-ui: avg ~0.52× fontSize for mixed-case
const texts = ['Build Better Systems.', 'Grow Faster Online.'];
const phones = [375, 390, 414, 430];
for \(const vw of [6.5, 7, 7.5]\) {
  console.log\('\\n--- ' + vw + 'vw ---'\);
  phones.forEach\(w => {
    const fs = \(vw/100\) * w;
    const avail = w - 48; // px-6 both sides
    texts.forEach\(t => {
      const textW = t.length * fs * 0.52;
      const fits = textW <= avail;
      console.log\(w + 'px | fs=' + fs.toFixed\(1\) + 'px | \\"' + t + '\\" → ' + textW.toFixed\(0\) + 'px vs ' + avail + 'px ' + \(fits ? '✓' : '✗ OVERFLOW'\)\);
    }\);
  }\);
}
")
